const items = $input.all();
return items.map(item => {
    const json = item.json;
    const payload = json.payload || {};
    const headers = payload.headers || [];

    // 1. Format-Agnostic Header Extraction
    const from = json.from || headers.find(h => h.name.toLowerCase() === 'from')?.value || 'unknown@example.com';
    const subject = json.subject || headers.find(h => h.name.toLowerCase() === 'subject')?.value || 'No Subject';

    const sender_email = from.includes('<') ? from.match(/<([^>]+)>/)[1] : from;

    // 2. Full Content Extraction Improvement
    let content = '';
    if (json.text) {
        content = json.text;
    } else if (json.html) {
        content = json.html.replace(/<[^>]*>/g, ' '); 
    } else if (payload.parts) {
        const textPart = payload.parts.find(p => p.mimeType === 'text/plain');
        if (textPart && textPart.body.data) {
            content = Buffer.from(textPart.body.data, 'base64').toString('utf8');
        }
    } else if (payload.body && payload.body.data) {
        content = Buffer.from(payload.body.data, 'base64').toString('utf8');
    }

    // Final fallback to snippet
    if (!content.trim()) content = json.snippet || '';

    return {
        json: {
            sender_email: sender_email.trim(),
            subject: subject.trim(),
            content: content.trim()
        }
    }
});
